export const CueHiveEventType = {
  Complete: 'complete',
  Dismissal: 'dismissal',
  Impression: 'impression',
} as const;

export type HiveEventType = (typeof CueHiveEventType)[keyof typeof CueHiveEventType];

export const CueLifecycle = {
  Closed: 'closed',
  Finished: 'finished',
  Shown: 'shown',
} as const;

export type CueLifecycleEvent = (typeof CueLifecycle)[keyof typeof CueLifecycle];

export type CueStepKey = string;

export type CueConfig = {
  persistSeenOn: readonly CueLifecycleEvent[];
  /** When omitted, analytics runs for every lifecycle passed to `emitCue`. */
  emitAnalyticsOn?: readonly CueLifecycleEvent[];
  stepKeys?: readonly CueStepKey[];
  analyticsDefaults?: Record<string, string>;
};
